protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name so existing documents
        // (which store "Discriminator": "Product") remain readable.
        // Without this, EF Core 9 defaults to "$type" and won't match old docs.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123") so that
        // FindAsync and point-reads work against existing documents.
        // Without this, EF Core 9 generates bare ids ("123").
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // HasIndex removed — Cosmos DB throws at startup in EF Core 9.
    // Manage indexing via Azure Portal, Bicep, or Terraform instead.
}

